import json
import psycopg2
import boto3
from utility.archive import archive
import logging
import os
import zipfile
import pandas as pd
from io import BytesIO
logger = logging.getLogger()
logger.setLevel(logging.INFO)
s3 = boto3.client("s3")

def copy(filedata,conn,curr):
    filename=filedata[0]
    file=filename.split(".")[0]
    filekey=filedata[4]
    bucketname=filedata[1]
    path=filekey.split("/")
    datetime=filedata[6].replace(" ","").replace(":","").replace("-","")
    pathbroke=''
    count=0
    for i in range(len(path)):
        if path[i]=='Land':
            count=i
            break
        pathbroke=f"{pathbroke}{path[i]}/"
    count+=1
    procpath=f"{pathbroke}Processed/"
    for i in range(count,len(path)-1):
        procpath=f"{procpath}{path[i]}/"
    procpath=f"{procpath}{file}/{datetime}/{filename}"
    copy_source = {
        'Bucket': bucketname,
        'Key': filekey
    }
    
    s3.copy_object(
        Bucket=bucketname,
        CopySource=copy_source,
        Key=procpath
    )
    # curr.execute("""update public.intrn_kna_nitya_lambdards set filestatus ='Copy Done' where filekey = (%s);""",(filekey,))
    logger.info("File processed and stored")
    archive(filedata,conn,curr)